// final class — can't be extended
final class ImmutableClass {
    // final variable — must be initialized once
    final int value;

    // Static final constant
    static final double PI = 3.14159;

    ImmutableClass(int value) {
        this.value = value;  // Initialized in constructor
    }

    void display() {
        System.out.println("Value: " + value);
        System.out.println("PI: " + PI);
        // value = 10;  // ERROR! Can't modify final variable
        // PI = 3.0;    // ERROR! Can't modify final constant
    }
}

// Can't extend a final class
// class SubClass extends ImmutableClass { } // ERROR!

// Regular class with final methods
class Parent {
    // final method — can't be overridden
    final void cannotOverride() {
        System.out.println("This method is final!");
    }

    void canOverride() {
        System.out.println("This method can be overridden");
    }
}

class Child extends Parent {
    @Override
    void canOverride() {
        System.out.println("Overridden successfully!");
    }

    // Can't override final method
    /*
    @Override
    void cannotOverride() {  // ERROR!
        System.out.println("Trying to override");
    }
    */
}

public class FinalExample {
    public static void main(String[] args) {
        // final local variables
        final int MAX_ATTEMPTS = 3;
        // MAX_ATTEMPTS = 5;  // ERROR! Can't modify

        System.out.println("Max attempts: " + MAX_ATTEMPTS);

        ImmutableClass obj = new ImmutableClass(42);
        obj.display();

        // obj.value = 100;  // ERROR! Can't modify

        Child child = new Child();
        child.canOverride();
        child.cannotOverride();  // Uses parent's final version
    }
}

